```class Solution {
public:
    int countNumbers(string l, string r, int b) {
        int count = 0;
        int base = b;
        int num = 0;

        while (l < r) {
            num = (num * base + stoi(l)) % 10 * base + stoi(r) % 10;
            count += (num >= 0 && num < base);
            l++;
            r++;
        }

        return count;
    }
};
